// Function to calculate the angle between hour and minute hands of a clock
static int calcAngle(double h, double m) {
  // Input validation
  if (h < 0 || m < 0 || h > 12 || m > 60) {
    std::cout << "Wrong input" << std::endl;
    // In Java, the method would continue, potentially returning a garbage value or
    // throwing an exception if not handled. For direct translation, we continue.
    // A more robust C++ approach might throw an exception or return a specific error code.
  }
  // Adjust h for 12 o'clock and m for 60 minutes
  if (h == 12) h = 0;
  if (m == 60) m = 0;
  // Calculate hour hand angle
  // 0.5 degrees per minute (360 degrees / (12 hours * 60 minutes/hour))
  int hour_angle = static_cast<int>(0.5 * (h * 60 + m));
  // Calculate minute hand angle
  // 6 degrees per minute (360 degrees / 60 minutes)
  int minute_angle = static_cast<int>(6 * m);
  // Calculate the absolute difference between the angles
  int angle = std::abs(hour_angle - minute_angle);
  // Return the smaller angle (e.g., 30 degrees instead of 330 degrees)
  angle = std::min(360 - angle, angle);
  return angle;
}

