        if (pre[i] < root) {
            return false;
        }
        // If pre[i] is greater than s.top(), then s.top() is the root of
        // the right subtree, and pre[i] is a node in that right subtree.
        // We pop elements from the stack until we find an element greater
        // than pre[i] or the stack becomes empty. The last popped element
        // becomes the new root.
