        a[m - 1][i] = val++;
      }
      m--; // Shrink bottom boundary
    }
    // Fill the first column from the remaining rows/columns (left boundary)
    // Only if there's still a column to process (i.e., l is still less than n,
    // meaning the left boundary hasn't crossed or met the right boundary)
    if (l < n) {
