// Function to solve the 0/1 Knapsack problem using recursion
// W: Capacity of the knapsack
// wt: A constant reference to a vector of weights of items
// val: A constant reference to a vector of values of items
// n: The number of items currently being considered (or the total number of items
//    in the initial call, decreasing with each recursive call)
int knapSack(int W, const std::vector<int>& wt, const std::vector<int>& val, int n) {
    // Base case: If no items are left to consider or the knapsack capacity is 0,
    // no value can be obtained.
    if (n == 0 || W == 0) {
        return 0;
    }
    // If the weight of the nth item (wt[n-1]) is greater than the current
    // knapsack capacity W, then this item cannot be included.
    // So, we move to the next item (n-1) without changing the capacity.
    if (wt[n - 1] > W) {
        return knapSack(W, wt, val, n - 1);
    }
    // Else (the nth item can be included), we consider two possibilities
    // and return the maximum of their results:
    // 1. Include the nth item:
    //    Add its value (val[n-1]) to the result of solving the knapsack problem
    //    with the remaining capacity (W - wt[n-1]) and the remaining items (n-1).
    // 2. Exclude the nth item:
    //    Solve the knapsack problem with the same capacity W and the remaining items (n-1).
    else {
        return std::max(
            val[n - 1] + knapSack(W - wt[n - 1], wt, val, n - 1), // Case 1: Include item
            knapSack(W, wt, val, n - 1)                          // Case 2: Exclude item
        );
    }
}

