static bool isSubsetSum(const int set[], int n, int sum) {
  // Create a 2D dynamic programming table (vector of vectors)
  // `n + 1` rows and `sum + 1` columns.
  // All elements are default initialized to false for bool.
  std::vector<std::vector<bool>> subset(n + 1, std::vector<bool>(sum + 1));
  // If sum is 0, then answer is true (empty subset)
  for (int i = 0; i <= n; i++) {
    subset[i][0] = true;
