  // If sum is not 0 and set is empty, then answer is false
  // (This loop is technically redundant if std::vector<bool> initializes to false,
  // but included for direct translation of explicit Java initialization)
  for (int i = 1; i <= sum; i++) {
    subset[0][i] = false;
  }
  // Fill the subset table in bottom-up manner
  for (int i = 1; i <= n; i++) {
    for (int j = 1; j <= sum; j++) {
      // If the current item's value (set[i-1]) is greater than the current sum 'j',
      // we cannot include it. So, the result is the same as without this item.
      if (j < set[i - 1]) {
        subset[i][j] = subset[i - 1][j];
      } else {
        // If we can include the item, then either we don't include it (subset[i-1][j])
        // OR we include it (subset[i-1][j - set[i-1]]).
        // The '||' operator combines these two possibilities.
        subset[i][j] = subset[i - 1][j] || subset[i - 1][j - set[i - 1]];
      }
    }
  }
  // The final result is stored at subset[n][sum]
  return subset[n][sum];
}

