    // Copy elements of 'arr' into the first 'n' positions of 'brr'.
    for (int i = 0; i < n; i++) {
        brr[i] = arr[i];
    }
    // Copy elements of 'arr' again into 'brr' starting from index 'n'.
    // This effectively creates 'arr' followed by 'arr'.
    for (int i = 0; i < n; i++) {
        brr[n + i] = arr[i];
    }
    int maxHam = 0; // Initialize maximum Hamming distance found so far.
    // Iterate through all possible non-zero rotations (shifts) of the array.
    // 'i' represents the number of positions the array is rotated.
    for (int i = 1; i < n; i++) {
