        // Calculate the Hamming distance between the original array 'arr'
        // and the 'i'-th rotation of 'arr' (simulated using 'brr').
        // 'j' iterates through the shifted part of 'brr'.
        // 'k' iterates through the original 'arr'.
        for (int j = i, k = 0; j < (i + n); j++, k++) {
