        // If the current Hamming distance is equal to 'n', it means all elements are different.
        // This is the maximum possible Hamming distance, so we can return immediately.
        if (currHam == n) {
            return n;
        }
        // Update 'maxHam' with the maximum of its current value and 'currHam'.
        maxHam = std::max(maxHam, currHam);
    }
    // Return the maximum Hamming distance found across all rotations.
    return maxHam;
