static int findMin(int arr[], int low, int high) {
  // If the array is not rotated at all (or has only one element),
  // the first element is the minimum.
  if (high < low) return arr[0];
  // If there is only one element left
  if (high == low) return arr[low];
  // Calculate mid
  int mid = low + (high - low) / 2;
  // Check if (mid+1) is the minimum element
  // Consider the cases like {3, 4, 5, 1, 2}
  if (mid < high && arr[mid + 1] < arr[mid]) return arr[mid + 1];
  // Check if mid itself is the minimum element
  // Consider the cases like {4, 5, 1, 2, 3}
  if (mid > low && arr[mid] < arr[mid - 1]) return arr[mid];
  // Decide whether to go to left or right half
  // If arr[high] > arr[mid], the minimum is in the left half
  // (including mid, but we already checked mid and mid+1)
  if (arr[high] > arr[mid]) return findMin(arr, low, mid - 1);
  // Else, the minimum is in the right half
  return findMin(arr, mid + 1, high);
}

