/**
 * Calculates the minimum number of coins required to make a given value V.
 * Uses dynamic programming.
 *
 * @param coins An array of available coin denominations.
 * @param m The number of coin denominations (size of the coins array).
 * @param V The target value for which to find the minimum coins.
 * @return The minimum number of coins required, or INT_MAX if it's not possible.
 */
int minCoins(const int coins[], int m, int V) {
    // Create a table to store results of subproblems.
    // table[i] will store the minimum number of coins for value i.
    std::vector<int> table(V + 1);
    // Base case: 0 coins are needed for value 0.
    table[0] = 0;
    // Initialize all table values to a very large number (representing infinity)
    // to indicate that they are not yet reachable.
    for (int i = 1; i <= V; i++) {
        table[i] = INT_MAX;
    }
    // Fill table entries for all values from 1 to V.
    for (int i = 1; i <= V; i++) {
        // Go through all coin denominations
        for (int j = 0; j < m; j++) {
            // If the current coin denomination is less than or equal to the current value i
            if (coins[j] <= i) {
                // Calculate the result for the remaining value (i - coins[j])
                int sub_res = table[i - coins[j]];
                // If a solution exists for sub_res (i.e., not INT_MAX)
                // and adding one more coin (coins[j]) gives a better result
                // than the current best for table[i]
                if (sub_res != INT_MAX && sub_res + 1 < table[i]) {
                    table[i] = sub_res + 1;
                }
            }
        }
    }
    // The result for value V is stored in table[V].
    return table[V];
}

