bool isHeap(const int arr[], int n) {
  for (int i = 0; i <= (n - 2) / 2; ++i) {
    // Check if left child violates the max-heap property
    // For a 0-indexed array, the left child of node i is at 2*i + 1.
    // The loop condition `i <= (n - 2) / 2` ensures that `2*i + 1`
    // will always be a valid index within the array bounds for `n > 0`.
    if (arr[2 * i + 1] > arr[i]) {
      return false;
    }
    // Check if right child exists and violates the max-heap property
    // For a 0-indexed array, the right child of node i is at 2*i + 2.
    // We must check if the right child index is within the array bounds (`< n`)
    // before accessing it.
    if (2 * i + 2 < n && arr[2 * i + 2] > arr[i]) {
      return false;
    }
  }
  // If no violations are found after checking all parent nodes, it is a max-heap.
  return true;
}

