static int findoptimal(int N) {
    // Base case: if N is 6 or less, the optimal value is N itself.
    if (N <= 6) {
        return N;
    }
    // Create a vector (dynamic array) to store the optimal values
    // for different N, up to the given N.
    // The size is N, and indices will correspond to (n-1) for value n.
    std::vector<int> screen(N);
    // Initialize the first 6 values based on the problem's observation
    // For n = 1 to 6, screen[n-1] = n
    for (int n = 1; n <= 6; ++n) {
        screen[n - 1] = n;
    }
    // Fill the remaining values using the dynamic programming approach
    // For n from 7 up to N:
    // screen[n-1] represents the optimal value for 'n' presses.
    // It's the maximum of three possibilities:
    // 1. 2 * screen[n-4]: (n-4) represents the number of presses to get some 'A's.
    //    Then, two presses (Ctrl+A, Ctrl+C) and one press (Ctrl+V) effectively doubles
    //    the 'A's from (n-4) presses. This corresponds to (n-4) + 3 presses.
    // 2. 3 * screen[n-5]: Similar logic, but with two Ctrl+V operations.
    //    (n-5) presses to get some 'A's, then Ctrl+A, Ctrl+C, Ctrl+V, Ctrl+V.
    //    This corresponds to (n-5) + 4 presses.
    // 3. 4 * screen[n-6]: Similar logic, but with three Ctrl+V operations.
    //    (n-6) presses to get some 'A's, then Ctrl+A, Ctrl+C, Ctrl+V, Ctrl+V, Ctrl+V.
    //    This corresponds to (n-6) + 5 presses.
    // Note: The problem description usually relates these to a sequence of operations
    // like (A, A, A, A, A, A, Ctrl+A, Ctrl+C, Ctrl+V, Ctrl+V) or (A, A, A, A, A, Ctrl+A, Ctrl+C, Ctrl+V, Ctrl+V, Ctrl+V) etc.
    // The indices (n-4, n-5, n-6) correctly map to the previous states.
    for (int n = 7; n <= N; ++n) {
        screen[n - 1] = std::max({2 * screen[n - 4], 3 * screen[n - 5], 4 * screen[n - 6]});
    }
    // The optimal value for N presses is stored at screen[N-1]
    return screen[N - 1];
}

