static int maxLength(const std::string& s, int n) {
    // Initialize a 2D vector (dynamic programming table) with dimensions n x n,
    // and all elements initialized to 0.
    std::vector<std::vector<int>> dp(n, std::vector<int>(n, 0));
    // Base case: Substrings of length 2
    // If s[i] is '(' and s[i+1] is ')', then dp[i][i+1] = 2
    for (int i = 0; i < n - 1; ++i) {
        if (s[i] == '(' && s[i + 1] == ')') {
            dp[i][i + 1] = 2;
        }
    }
    // Fill the DP table for increasing substring lengths (l)
    // l represents the length of the substring minus 1 (j - i)
    // So, l=2 means substring length 3, l=3 means substring length 4, etc.
    for (int l = 2; l < n; ++l) { // l is the difference j - i
        // Iterate through all possible starting indices 'i' for the current length 'l'
        for (int i = 0; i < n - l; ++i) {
            int j = i + l; // Calculate the corresponding ending index 'j'
            // Case 1: If the substring s[i...j] forms a valid pair
            // i.e., s[i] is '(' and s[j] is ')'
            // Then, the length is 2 (for the outer pair) + the length of the substring s[i+1...j-1]
            if (s[i] == '(' && s[j] == ')') {
                dp[i][j] = 2 + dp[i + 1][j - 1];
            }
            // Case 2: The substring s[i...j] can be formed by concatenating two valid
            // parenthesis substrings s[i...k] and s[k+1...j]
            // We take the maximum of all such possible splits
            for (int k = i; k < j; ++k) {
                dp[i][j] = std::max(dp[i][j], dp[i][k] + dp[k + 1][j]);
            }
        }
    }
    // The result for the entire string s[0...n-1] is stored in dp[0][n-1]
    return dp[0][n - 1];
}

