int MinimumCost(int cost[], int n_original, int W) {
    std::vector<int> val;
    std::vector<int> wt;
    int size = 0;
    // Filter out items with cost -1
    for (int i = 0; i < n_original; i++) {
        if (cost[i] != -1) {
            val.push_back(cost[i]);
            wt.push_back(i + 1); // Weight is (index + 1)
            size++;
        }
    }
    // Update n to be the number of valid items
    int n = size;
    // Create a 2D vector for dynamic programming table
    // min_cost[i][j] will store the minimum cost to achieve weight j using first i items
    std::vector<std::vector<int>> min_cost(n + 1, std::vector<int>(W + 1));
    // Initialize the first row (no items chosen) with a very large value
    // as it's impossible to achieve any weight without items
    for (int i = 0; i <= W; i++) {
        min_cost[0][i] = INT_MAX;
    }
    // Initialize the first column (weight 0) with cost 0
    // as it costs 0 to achieve a weight of 0
    for (int i = 1; i <= n; i++) {
        min_cost[i][0] = 0;
    }
    // Fill the DP table
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= W; j++) {
            // If current item's weight is more than current capacity j,
            // we cannot include it. So, cost is same as without this item.
            if (wt[i - 1] > j) {
                min_cost[i][j] = min_cost[i - 1][j];
            } else {
                // Otherwise, we have two choices:
                // 1. Exclude the current item: min_cost[i - 1][j]
                // 2. Include the current item: min_cost[i][j - wt[i - 1]] + val[i - 1]
                //    (Note: This is a knapsack-like problem where items can be used multiple times,
                //     hence min_cost[i][...] not min_cost[i-1][...])
                // We take the minimum of these two choices.
                // We also need to be careful with INT_MAX + value, it might overflow.
                // If min_cost[i][j - wt[i - 1]] is INT_MAX, adding anything to it would be problematic.
                // So, we add a check to prevent overflow when calculating the 'include' path.
                int value_if_included = INT_MAX;
                if (min_cost[i][j - wt[i - 1]] != INT_MAX) {
                    value_if_included = min_cost[i][j - wt[i - 1]] + val[i - 1];
                }
                min_cost[i][j] = std::min(min_cost[i - 1][j], value_if_included);
            }
        }
    }
