// Function to validate an ISBN-10 string
// Assumes ASCII/UTF-8 compatible character encoding where '0' through '9' are contiguous.
static bool isValidISBN(const std::string& isbn) {
  // ISBN-10 must be exactly 10 characters long
  int n = isbn.length();
  if (n != 10) {
    return false;
  }
  int sum = 0;
  // Process the first 9 characters
  for (int i = 0; i < 9; i++) {
    char current_char = isbn[i];
    // Each of the first 9 characters must be a digit '0'-'9'
    if (current_char < '0' || current_char > '9') {
      return false;
    }
    // Convert character digit to integer
    int digit = current_char - '0';
    // Calculate weighted sum
    sum += (digit * (10 - i));
  }
  // Process the 10th (last) character
  char last_char = isbn[9];
  // The last character can be a digit '0'-'9' or 'X' (for 10)
  if (last_char != 'X' && (last_char < '0' || last_char > '9')) {
    return false;
  }
  // Add the value of the last character to the sum
  // 'X' counts as 10, otherwise it's its digit value
  sum += ((last_char == 'X') ? 10 : (last_char - '0'));
  // An ISBN-10 is valid if the sum is divisible by 11
  return (sum % 11 == 0);
}

