int findMinimumAngle(const int arr[], int n) {
  int l = 0;
  int sum = 0;
  int ans = 360; // Initialize with the maximum possible angle
  for (int i = 0; i < n; ++i) {
    sum += arr[i]; // Expand window to the right
    // While the current sum is 180 or more, we have a candidate angle.
    // Shrink the window from the left and update 'ans'.
    while (sum >= 180) {
      ans = std::min(ans, 2 * std::abs(180 - sum));
      sum -= arr[l]; // Shrink window from the left
      l++;           // Move left pointer
