  // 1. Take the element from the left end (a[low])
  // 2. Take the element from the right end (a[high])
  dp[low][high] = std::max(
    a[low] * turn + solve(dp, a, low + 1, high, turn + 1), // Choose low
    a[high] * turn + solve(dp, a, low, high - 1, turn + 1)  // Choose high
  );
