static int minRemovalsDP(int arr[], int n) {
    int longest_start = -1;
    int longest_end = 0; // Initialize to 0, will be updated if a valid segment is found
    for (int start = 0; start < n; start++) {
        int min_val = std::numeric_limits<int>::max(); // Equivalent to Integer.MAX_VALUE
        int max_val = std::numeric_limits<int>::min(); // Equivalent to Integer.MIN_VALUE
        for (int end = start; end < n; end++) {
            int val = arr[end];
            if (val < min_val) {
                min_val = val;
            }
            if (val > max_val) {
                max_val = val;
            }
            // Check the condition: 2 * min <= max
            if (2 * min_val <= max_val) {
                break; // Break the inner loop if condition is met
            }
            // Update longest_start and longest_end if the current segment is longer
            // or if it's the first valid segment found
            if (end - start > longest_end - longest_start || longest_start == -1) {
                longest_start = start;
                longest_end = end;
            }
        }
    }
    // If no valid segment was found, longest_start remains -1
    if (longest_start == -1) {
        return n; // All elements must be removed
    }
    // Calculate the length of the longest valid segment
    int longest_segment_length = longest_end - longest_start + 1;
    // The number of removals is n minus the length of the longest valid segment
    return (n - longest_segment_length);
}
