void stoogesort(int arr[], int l, int h) {
  if (l >= h) {
    return;
  }
  // If arr[l] > arr[h], swap them
  if (arr[l] > arr[h]) {
    int t = arr[l];
    arr[l] = arr[h];
    arr[h] = t;
  }
  // If there are more than 2 elements in the subarray
  if (h - l + 1 > 2) {
    int t = (h - l + 1) / 3; // Calculate 1/3 of the size
    // Recursively sort the first 2/3 part
    stoogesort(arr, l, h - t);
    // Recursively sort the last 2/3 part
    stoogesort(arr, l + t, h);
    // Recursively sort the first 2/3 part again
    stoogesort(arr, l, h - t);
  }
}

